import{_ as a,o as t,c as o,S as i}from"./chunks/framework.DZlzLDBr.js";const u=JSON.parse('{"title":"Multiple Choice Questions","description":"","frontmatter":{},"headers":[],"relativePath":"Multiple-Choice-Questions.md","filePath":"Multiple-Choice-Questions.md","lastUpdated":null}'),n={name:"Multiple-Choice-Questions.md"};function s(r,e,l,d,c,p){return t(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="multiple-choice-questions" tabindex="-1">Multiple Choice Questions <a class="header-anchor" href="#multiple-choice-questions" aria-label="Permalink to &quot;Multiple Choice Questions&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>MCQ cards show one question with multiple options. You choose one answer.</p><h2 id="writing-an-mcq-card" tabindex="-1">Writing an MCQ card <a class="header-anchor" href="#writing-an-mcq-card" aria-label="Permalink to &quot;Writing an MCQ card&quot;">​</a></h2><p>Use <code>MCQ</code> for the question stem, <code>A</code> for the correct answer, and <code>O</code> for each incorrect option:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T | French Capitals |</span></span>
<span class="line"><span>MCQ | What is the capital of France? |</span></span>
<span class="line"><span>A | Paris |</span></span>
<span class="line"><span>O | London |</span></span>
<span class="line"><span>O | Berlin |</span></span>
<span class="line"><span>O | Madrid |</span></span>
<span class="line"><span>I | Remember: it&#39;s on the Seine |</span></span>
<span class="line"><span>G | Geography |</span></span></code></pre></div><ul><li><code>MCQ</code>: required question stem.</li><li><code>A</code>: required correct answer (one).</li><li><code>O</code>: required incorrect options (one or more).</li></ul><h2 id="using-the-modal" tabindex="-1">Using the modal <a class="header-anchor" href="#using-the-modal" aria-label="Permalink to &quot;Using the modal&quot;">​</a></h2><ol><li>Right-click in a note → <strong>Add flashcard → MCQ Card</strong>.</li><li>Enter the question stem.</li><li>Enter the correct answer.</li><li>Add incorrect options (click <strong>Add option</strong> for more).</li><li>Optionally add title, info, and groups.</li><li>Click <strong>Save</strong>.</li></ol><h2 id="how-mcqs-are-reviewed" tabindex="-1">How MCQs are reviewed <a class="header-anchor" href="#how-mcqs-are-reviewed" aria-label="Permalink to &quot;How MCQs are reviewed&quot;">​</a></h2><p>During review, options are shown as buttons. Select one option.</p><ul><li>Correct: selected option turns green, grade is <strong>Good</strong>.</li><li>Incorrect: selected option turns red, correct option is highlighted, grade is <strong>Again</strong>.</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>MCQ grading is automatic. You do not press a separate grade button.</p></div><h3 id="option-randomisation" tabindex="-1">Option randomisation <a class="header-anchor" href="#option-randomisation" aria-label="Permalink to &quot;Option randomisation&quot;">​</a></h3><p>By default, options stay in the order you wrote. Enable <strong>Randomise MCQ options</strong> in <strong>Settings → Study</strong> to shuffle order each time.</p><h2 id="grading-behaviour" tabindex="-1">Grading behaviour <a class="header-anchor" href="#grading-behaviour" aria-label="Permalink to &quot;Grading behaviour&quot;">​</a></h2><p>MCQs are <strong>auto-graded</strong> based on your selection:</p><table tabindex="0"><thead><tr><th>Your choice</th><th>Grade applied</th></tr></thead><tbody><tr><td>Correct option</td><td><strong>Good</strong></td></tr><tr><td>Incorrect option</td><td><strong>Again</strong></td></tr></tbody></table><p>The FSRS scheduler then updates the card&#39;s scheduling data based on the grade, just like any other card type. See <a href="./Grading">Grading</a> for more on how grading works.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Write plausible distractors (wrong options) — if options are obviously wrong, the card isn&#39;t testing real knowledge.</li><li>Use MCQs for topics where distinguishing between similar items is the learning goal.</li><li>Combine with the <code>I</code> field to explain why the correct answer is right.</li></ul>`,22)])])}const g=a(n,[["render",s]]);export{u as __pageData,g as default};
